package Assignments_22_05_2026;

public class Sum_10_NaturalNumber {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		  int sum = 0;

		   // Loop from 1 to 10

	        for (int i = 1; i <= 10; i++) {

	            sum = sum + i;
	        }
	        
	        System.out.println("Sum of first 10 natural numbers is: " + sum);

	    }

	}